import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int data;
        Node next;
        Node(int d) { data = d; }
    }
    static int getLength(Node head) {
        int cnt = 0;
        while (head != null) {
            cnt++;
            head = head.next;
        }
        return cnt;
    }
    public static void main(String[] args) throws Exception {
        // Read entire input as raw string
        String raw = new String(System.in.readAllBytes());
        // Convert literal "\n" sequences to actual newlines
        raw = raw.replace("\\n", "\n");
        // Use Scanner to parse integers, it will treat any whitespace (including newlines) as delimiter
        Scanner sc = new Scanner(new StringReader(raw));
        StringBuilder out = new StringBuilder();
        if (!sc.hasNextInt()) {
            System.out.print("");
            return;
        }
        int T = sc.nextInt();
        for (int tc = 0; tc < T; tc++) {
            if (!sc.hasNextInt()) break;
            int N = sc.nextInt();
            Node head = null, tail = null;
            for (int i = 0; i < N; i++) {
                int val = sc.nextInt();
                Node nd = new Node(val);
                if (head == null) {
                    head = tail = nd;
                } else {
                    tail.next = nd;
                    tail = nd;
                }
            }
            out.append(getLength(head)).append('\n');
        }
        System.out.print(out.toString());
    }
}

